6592 static bool impliesPoison(const Value *ValAssumedPoison, const Value *V,
6593                           unsigned Depth) {
6594   if (isGuaranteedNotToBePoison(ValAssumedPoison))
6595     return true;
6596 
6597   if (directlyImpliesPoison(ValAssumedPoison, V, /* Depth */ 0))
6598     return true;
6599 
6600   const unsigned MaxDepth = 2;
6601   if (Depth >= MaxDepth)
6602     return false;
6603 
6604   const auto *I = dyn_cast<Instruction>(ValAssumedPoison);
6605   if (I && !canCreatePoison(cast<Operator>(I))) {
6606     return all_of(I->operands(), [=](const Value *Op) {
6607       return impliesPoison(Op, V, Depth + 1);
6608     });
6609   }
6610   return false;
6611 }
