6829 bool llvm::isGuaranteedToTransferExecutionToSuccessor(const Instruction *I) {
6830   // Note: An atomic operation isn't guaranteed to return in a reasonable amount
6831   // of time because it's possible for another thread to interfere with it for an
6832   // arbitrary length of time, but programs aren't allowed to rely on that.
6833 
6834   // If there is no successor, then execution can't transfer to it.
6835   if (isa<ReturnInst>(I))
6836     return false;
6837   if (isa<UnreachableInst>(I))
6838     return false;
